function imgExst = fMspcShtLstV01(espcDir,nmbSht,camNmb)% imgExst = fMspcShtLstV01(espcDir,nmbSht,camNmb);% give a list of image exist logic % against specific camera%% imgExst: logic of image exist% espcDir: directory to check image% nmbSht: number of shots from trex logfile% camNmb: camera number%% Function to get magspec shot list, ver.1%% Kei Nakamura% Created on Tuesday, June 2nd 2009.% Modified on%% bodyname = ['/*cam',num2str(camNmb),'.png'];inf = dir([espcDir,name]);         % information for Scan* file[nmbImg,dlt] = size(inf);   % number of imagesimgNmb(1) = 0;kk = 1;     % index for actual shot takenfor jj=1:nmbImg    name = inf(jj).name;    if max(size(name))<15        pp = find(name=='c');        imgNmb(kk) = str2num(name(1:pp-1));  % scan number        kk = kk +1;    endendnmbImg = kk-1;  % number of imageimgExst = zeros(nmbSht,1);        % array for shot existif imgNmb(1)~=0    imgExst(imgNmb) = 1;end
